// Mirrors the shape of types like React.ReactNode: an exported alias whose
// resolved union includes `undefined`, declared outside the consumer project.
export type FakeUndefinedUnion = string | number | undefined;
export type FakeNonUndefinedUnion = string | number;

// Mirrors Vue's `MaybeRef<T> = T | Ref<T>`: an external generic that
// distributes its type argument into the resolved top-level union.
export type FakeMaybeRef<T> = T | { ref: T };